const input = $json.body ?? $json;
const missing = [];
const isNumber = (value) => typeof value === 'number' && Number.isFinite(value);

if (!input.usuario || typeof input.usuario !== 'string') missing.push('usuario');
if (!input.dispositivo?.nombre) missing.push('dispositivo.nombre');
if (!input.dispositivo?.version) missing.push('dispositivo.version');
if (!isNumber(input.ubicacion?.lat)) missing.push('ubicacion.lat');
if (!isNumber(input.ubicacion?.lon)) missing.push('ubicacion.lon');
if (!('altitud' in (input.ubicacion ?? {}))) missing.push('ubicacion.altitud');
if (!('precision' in (input.ubicacion ?? {}))) missing.push('ubicacion.precision');
if (!('velocidad' in (input.movimiento ?? {}))) missing.push('movimiento.velocidad');
if (!input.movimiento?.marca_tiempo || Number.isNaN(Date.parse(input.movimiento.marca_tiempo))) missing.push('movimiento.marca_tiempo');
if (!('bateria' in (input.estado ?? {}))) missing.push('estado.bateria');

const latitudeValid = isNumber(input.ubicacion?.lat) && input.ubicacion.lat >= -90 && input.ubicacion.lat <= 90;
const longitudeValid = isNumber(input.ubicacion?.lon) && input.ubicacion.lon >= -180 && input.ubicacion.lon <= 180;
if (isNumber(input.ubicacion?.lat) && !latitudeValid) missing.push('ubicacion.lat fuera de rango');
if (isNumber(input.ubicacion?.lon) && !longitudeValid) missing.push('ubicacion.lon fuera de rango');

const battery = input.estado?.bateria;
if (battery !== null && (!isNumber(battery) || battery < 0 || battery > 1)) missing.push('estado.bateria fuera de rango');

return [{
  json: {
    valido: missing.length === 0,
    mensaje: missing.length === 0 ? 'Telemetría recibida correctamente' : 'Payload inválido',
    errores: missing,
    recibido_en: new Date().toISOString(),
    telemetria: {
      usuario: input.usuario ?? null,
      dispositivo: {
        nombre: input.dispositivo?.nombre ?? null,
        version: input.dispositivo?.version ?? null
      },
      ubicacion: {
        lat: input.ubicacion?.lat ?? null,
        lon: input.ubicacion?.lon ?? null,
        altitud: input.ubicacion?.altitud ?? null,
        precision: input.ubicacion?.precision ?? null
      },
      movimiento: {
        velocidad: input.movimiento?.velocidad ?? null,
        marca_tiempo: input.movimiento?.marca_tiempo ?? null
      },
      estado: { bateria: battery ?? null }
    }
  },
  pairedItem: { item: 0 }
}];
